import{_ as a,o as i,c as e,ak as r}from"./chunks/framework.CY1a07lP.js";const _=JSON.parse('{"title":"注意事项","description":"","frontmatter":{},"headers":[],"relativePath":"main/notice.md","filePath":"main/notice.md","lastUpdated":1777866000000}'),o={name:"main/notice.md"};function t(n,l,c,d,s,h){return i(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h1><div class="warning custom-block"><p class="custom-block-title">注意</p><p>本章将详细介绍在玩游戏之前你应该知道的事。务必遵守。</p></div><h2 id="重要须知" tabindex="-1">重要须知 <a class="header-anchor" href="#重要须知" aria-label="Permalink to “重要须知”">​</a></h2><ol><li>实体数量限制：请勿使过多实体（生物、掉落物、矿车等）堆积在同一位置。</li><li>挂机安全自负：挂机请在安全区域进行，服务器对挂机状态下的任何损失概不负责。</li><li>领地与财产：私人领地外放置的物品无保护，被拿取恕不负责，请务必妥善圈地。</li><li>服务器为死亡掉落机制，无法保证死亡后装备可被寻回。</li><li>交易谨慎：玩家间交易请谨慎。如遇明确骗子，可向服务器或群内举报，核实后将严肃处理。</li><li>一个游戏周目的持续时间大约为3到4个月，具体时长可能有所不同。每个新周目开启时，所有玩家的资产、领地、游戏币及地图等数据都将被重置。如果有因为新周目重置导致的损失，服务器不负任何责任。</li></ol><h2 id="禁止的行为" tabindex="-1">禁止的行为 <a class="header-anchor" href="#禁止的行为" aria-label="Permalink to “禁止的行为”">​</a></h2><ol><li>禁止作弊：严禁任何形式的作弊行为。</li><li>禁止攻击萌新：严禁恶意攻击或击杀新手玩家，违者将受严惩。</li><li>禁止破坏行为：严禁利用漏洞、恶意卡服等任何破坏服务器稳定与游戏公平的行为。</li><li>禁止恶意互动：禁止刷屏、辱骂、人身攻击等行为，违规者将面临相应处罚。</li></ol><h2 id="处罚细则" tabindex="-1">处罚细则 <a class="header-anchor" href="#处罚细则" aria-label="Permalink to “处罚细则”">​</a></h2><ol><li>辱骂谩骂：首次两次警告，第三次游戏内禁言 15分钟。</li><li>恶意挑衅/人身攻击：首次两次警告，第三次关小黑屋 30分钟（下线不计时）。</li><li>恶意引诱击杀萌新：首次一次警告，第二次关小黑屋 3小时（下线不计时）。</li></ol><h2 id="纠纷处理原则" tabindex="-1">纠纷处理原则 <a class="header-anchor" href="#纠纷处理原则" aria-label="Permalink to “纠纷处理原则”">​</a></h2><ol><li>物品纠纷：对于未圈地保护的物品被他人拿取的情况，因无圈地记录，服主不予查询及退还。</li><li>恶意报复：若失物者对拾取者实施过度（如多次、无限）恶意报复，服主将介入处理。主要责任在未圈地方，但过度报复行为亦不被允许。</li></ol><h2 id="游戏币" tabindex="-1">游戏币 <a class="header-anchor" href="#游戏币" aria-label="Permalink to “游戏币”">​</a></h2><ul><li>在本服务器中，游戏币的基本单位是G</li><li>游戏币可以送给别人<code>/pay 玩家 金额</code></li><li>每个新周目，游戏币都会清空，从头开始</li></ul><h3 id="如何获得游戏币" tabindex="-1">如何获得游戏币 <a class="header-anchor" href="#如何获得游戏币" aria-label="Permalink to “如何获得游戏币”">​</a></h3><ul><li>给其他玩家打工</li><li>主城商人收购</li><li>在线时长奖励</li><li>与其他玩家交易</li><li>和其他玩家交易 <strong>如果明确对方是个骗子，可以在服务器或者群里面反应</strong></li><li>全球商店 使用<code>/zah 价格 数量</code>出售手上的物品 使用<code>/菜单</code>查看全球商店</li></ul>',14)])])}const p=a(o,[["render",t]]);export{_ as __pageData,p as default};
